200→// ── WebSocket handler ────────────────────────────────────────────────
201→
202→pub async fn ws_handler(
203→    ws: WebSocketUpgrade,
204→    State(state): State<Arc<AppState>>,
205→) -> impl IntoResponse {
206→    ws.on_upgrade(move |socket| handle_socket(socket, state))
207→}
208→
209→async fn handle_socket(socket: WebSocket, state: Arc<AppState>) {
210→    let (sender, receiver) = socket.split();
211→    let rx = state.ws_tx.subscribe();
212→    run_socket_loop(sender, receiver, rx).await;
213→}
214→
215→/// WebSocket handler that accepts a broadcast sender directly (for use with server router).
216→pub async fn ws_handler_with_sender(
217→    ws: WebSocketUpgrade,
218→    tx: broadcast::Sender<String>,
219→) -> impl IntoResponse {
220→    ws.on_upgrade(move |socket| handle_socket_with_sender(socket, tx))
221→}
222→
223→async fn handle_socket_with_sender(socket: WebSocket, tx: broadcast::Sender<String>) {
224→    let (sender, receiver) = socket.split();
225→    let rx = tx.subscribe();
226→    run_socket_loop(sender, receiver, rx).await;
227→}
228→
229→/// Core WebSocket loop with ping/pong keepalive.
230→///
231→/// Combines broadcast forwarding, client message receiving, and periodic
232→/// ping/pong health checking into a single select loop. If no Pong is
233→/// received within [`PONG_TIMEOUT`] after a Ping is sent, the connection
234→/// is considered dead and the loop exits.
235→async fn run_socket_loop(
236→    mut sender: SplitSink<WebSocket, Message>,
237→    mut receiver: SplitStream<WebSocket>,
238→    mut rx: broadcast::Receiver<String>,
239→) {
240→    let mut ping_interval = tokio::time::interval(PING_INTERVAL);
241→    // The first tick completes immediately; consume it so the first real
242→    // ping fires after PING_INTERVAL has elapsed.
243→    ping_interval.tick().await;
244→
245→    let mut last_pong = Instant::now();
246→    let mut awaiting_pong = false;
247→
248→    loop {
249→        tokio::select! {
250→            // ── Periodic ping ───────────────────────────────────────
251→            _ = ping_interval.tick() => {
252→                // Check if the previous ping timed out
253→                if awaiting_pong && last_pong.elapsed() > PONG_TIMEOUT {
254→                    // Connection is dead — no pong received in time
255→                    break;
256→                }
257→                if sender.send(Message::Ping(vec![].into())).await.is_err() {
258→                    break;
259→                }
260→                awaiting_pong = true;
261→            }
262→
263→            // ── Broadcast forwarding ────────────────────────────────
264→            result = rx.recv() => {
265→                match result {
266→                    Ok(msg) => {
267→                        if sender.send(Message::Text(msg.into())).await.is_err() {
268→                            break;
269→                        }
270→                    }
271→                    Err(broadcast::error::RecvError::Closed) => break,
272→                    Err(broadcast::error::RecvError::Lagged(_)) => {
273→                        // Missed some messages; continue receiving
274→                        continue;
275→                    }
276→                }
277→            }
278→
279→            // ── Client messages (pong, close, etc.) ─────────────────
280→            msg = receiver.next() => {
281→                match msg {
282→                    Some(Ok(Message::Pong(_))) => {
283→                        last_pong = Instant::now();
284→                        awaiting_pong = false;
285→                    }
286→                    Some(Ok(Message::Close(_))) | None => break,
287→                    Some(Ok(_)) => {
288→                        // Ignore other messages from client (Text, Binary, Ping)
289→                    }
290→                    Some(Err(_)) => break,
291→                }
292→            }
293→        }
294→    }
295→
296→    // Best-effort close frame
297→    let _ = sender.send(Message::Close(None)).await;
298→}
299→
300→// ── Broadcast helper ─────────────────────────────────────────────────
301→
302→/// Serialize and broadcast a WsMessage to all connected WebSocket clients.
303→/// Returns silently even if no clients are connected.
304→pub fn broadcast_message(tx: &broadcast::Sender<String>, msg: &WsMessage) {
305→    match serde_json::to_string(msg) {
306→        Ok(json) => {
307→            let _ = tx.send(json); // Ignore error if no receivers
308→        }
309→        Err(e) => {
310→            eprintln!("[ws] Failed to serialize WsMessage: {}", e);
311→        }
312→    }
313→}
