 94→pub enum ApiError {
 95→    NotFound(String),
 96→    BadRequest(String),
 97→    Internal(String),
 98→}
 99→
100→impl IntoResponse for ApiError {
101→    fn into_response(self) -> Response {
102→        let (status, message) = match self {
103→            ApiError::NotFound(msg) => (StatusCode::NOT_FOUND, msg),
104→            ApiError::BadRequest(msg) => (StatusCode::BAD_REQUEST, msg),
105→            ApiError::Internal(msg) => (StatusCode::INTERNAL_SERVER_ERROR, msg),
106→        };
107→        (status, Json(serde_json::json!({"error": message}))).into_response()
108→    }
109→}
110→
111→impl From<FactoryError> for ApiError {
112→    fn from(e: FactoryError) -> Self {
113→        match e {
114→            FactoryError::ProjectNotFound { id } => {
115→                ApiError::NotFound(format!("Project {} not found", id))
116→            }
117→            FactoryError::IssueNotFound { id } => {
118→                ApiError::NotFound(format!("Issue {} not found", id))
119→            }
120→            FactoryError::RunNotFound { id } => {
121→                ApiError::NotFound(format!("Pipeline run {} not found", id))
122→            }
123→            FactoryError::LockPoisoned => ApiError::Internal("Internal lock poisoned".to_string()),
124→            FactoryError::BadRequest(msg) => ApiError::BadRequest(msg),
125→            FactoryError::InvalidColumn { column, message } => {
126→                ApiError::BadRequest(format!("Invalid column '{}': {}", column, message))
127→            }
128→            FactoryError::PipelineAlreadyRunning { issue_id } => {
129→                ApiError::BadRequest(format!("Pipeline already running for issue {}", issue_id))
130→            }
131→            FactoryError::GitHub(msg) => ApiError::Internal(format!("GitHub API error: {}", msg)),
132→            FactoryError::Database(e) => ApiError::Internal(e.to_string()),
133→            FactoryError::Other(e) => ApiError::Internal(e.to_string()),
134→        }
135→    }
136→}
