202→/// Extract "owner/repo" from various GitHub URL formats.
203→fn parse_github_owner_repo(url: &str) -> Option<String> {
204→    let url = url.trim().trim_end_matches('/').trim_end_matches(".git");
205→    // Handle https://github.com/owner/repo and https://TOKEN@github.com/owner/repo
206→    if let Some(github_pos) = url.find("github.com/") {
207→        let rest = &url[github_pos + "github.com/".len()..];
208→        let parts: Vec<&str> = rest.splitn(3, '/').collect();
209→        if parts.len() >= 2 && !parts[0].is_empty() && !parts[1].is_empty() {
210→            return Some(format!("{}/{}", parts[0], parts[1]));
211→        }
212→    }
213→    if let Some(rest) = url.strip_prefix("git@github.com:") {
214→        let parts: Vec<&str> = rest.splitn(3, '/').collect();
215→        if parts.len() >= 2 {
216→            return Some(format!("{}/{}", parts[0], parts[1]));
217→        }
218→    }
219→    // Bare "owner/repo" format
220→    let parts: Vec<&str> = url.splitn(3, '/').collect();
221→    if parts.len() == 2 && !parts[0].contains(':') && !parts[0].contains('.') {
222→        return Some(format!("{}/{}", parts[0], parts[1]));
223→    }
224→    None
225→}
