 16→/// Decision for where to move an issue after pipeline completion.
 17→#[derive(Debug, Clone, PartialEq)]
 18→pub enum PromoteDecision {
 19→    /// Clean run — move to Done.
 20→    Done,
 21→    /// Has warnings or issues — move to InReview.
 22→    InReview,
 23→    /// Pipeline failed — stay as-is.
 24→    Failed,
 25→}
 26→
 27→/// Policy for auto-promoting issues after pipeline completion.
 28→pub struct AutoPromotePolicy;
 29→
 30→impl AutoPromotePolicy {
 31→    /// Decide where to move an issue based on pipeline results.
 32→    ///
 33→    /// - `pipeline_succeeded`: did the pipeline complete without failures?
 34→    /// - `has_review_warnings`: did any review produce warnings?
 35→    /// - `arbiter_proceeded`: did the arbiter have to PROCEED past findings?
 36→    /// - `fix_attempts`: how many fix cycles were needed?
 37→    pub fn decide(
 38→        pipeline_succeeded: bool,
 39→        has_review_warnings: bool,
 40→        arbiter_proceeded: bool,
 41→        fix_attempts: u32,
 42→    ) -> PromoteDecision {
 43→        if !pipeline_succeeded {
 44→            return PromoteDecision::Failed;
 45→        }
 46→        if has_review_warnings || arbiter_proceeded || fix_attempts > 0 {
 47→            return PromoteDecision::InReview;
 48→        }
 49→        PromoteDecision::Done
 50→    }
 51→}
