 53→fn translate_host_path_to_container(path: &str) -> String {
 54→    if path.contains("/.forge/repos/")
 55→        && !path.starts_with("/app/")
 56→        && let Some(pos) = path.find("/.forge/repos/")
 57→    {
 58→        return format!("/app{}", &path[pos..]);
 59→    }
 60→    path.to_string()
 61→}
