 63→/// Per-project mutex map that serializes git-mutating operations.
 64→/// Long-running agent execution remains parallel — only short git
 65→/// mutations (checkout, merge, push) are serialized.
 66→#[derive(Clone, Default)]
 67→pub struct GitLockMap {
 68→    locks: Arc<tokio::sync::Mutex<HashMap<String, Arc<tokio::sync::Mutex<()>>>>>,
 69→}
 70→
 71→impl GitLockMap {
 72→    pub async fn get(&self, project_path: &str) -> Arc<tokio::sync::Mutex<()>> {
 73→        let project_path = translate_host_path_to_container(project_path);
 74→        let canonical = match tokio::fs::canonicalize(&project_path).await {
 75→            Ok(p) => p.to_string_lossy().to_string(),
 76→            Err(e) => {
 77→                eprintln!(
 78→                    "[pipeline] Failed to canonicalize '{}': {}. Using raw path for git lock.",
 79→                    project_path, e
 80→                );
 81→                project_path.trim_end_matches('/').to_string()
 82→            }
 83→        };
 84→        let mut map = self.locks.lock().await;
 85→        map.entry(canonical)
 86→            .or_insert_with(|| Arc::new(tokio::sync::Mutex::new(())))
 87→            .clone()
 88→    }
 89→}
