 99→/// Convert a title to a URL-safe slug, limited to `max_len` characters.
100→pub fn slugify(title: &str, max_len: usize) -> String {
101→    let slug: String = title
102→        .to_lowercase()
103→        .chars()
104→        .map(|c| if c.is_alphanumeric() { c } else { '-' })
105→        .collect::<String>()
106→        .split('-')
107→        .filter(|s| !s.is_empty())
108→        .collect::<Vec<_>>()
109→        .join("-");
110→    if slug.len() > max_len {
111→        slug[..slug.floor_char_boundary(max_len)]
112→            .trim_end_matches('-')
113→            .to_string()
114→    } else {
115→        slug
116→    }
117→}
