119→/// Create a git branch for the pipeline run. Returns the branch name.
120→async fn create_git_branch(project_path: &str, issue_id: i64, issue_title: &str) -> Result<String> {
121→    let slug = slugify(issue_title, 40);
122→    let branch_name = format!("forge/issue-{}-{}", issue_id, slug);
123→
124→    let status = tokio::process::Command::new("git")
125→        .args(["checkout", "-b", &branch_name])
126→        .current_dir(project_path)
127→        .stdout(Stdio::null())
128→        .stderr(Stdio::piped())
129→        .status()
130→        .await
131→        .context("Failed to run git checkout -b")?;
132→
133→    if !status.success() {
134→        anyhow::bail!("Failed to create branch: {}", branch_name);
135→    }
136→
137→    Ok(branch_name)
138→}
