399→/// `POST /api/projects/clone` — clone a GitHub repository and register it.
400→///
401→/// Accepts a GitHub URL, shorthand (`owner/repo`), HTTPS URL, or SSH URL.
402→/// If a GitHub token is connected, it is injected for authentication.
403→///
404→/// **Request body:**
405→/// ```json
406→/// { "repo_url": "https://github.com/owner/repo" }
407→/// ```
408→///
409→/// **Response:** `201 Created` with the created `Project` as JSON.
410→///
411→/// **Errors:**
412→/// - `400 Bad Request` if the URL is unparseable or `git clone` fails
413→/// - `500 Internal Server Error` on filesystem or DB errors
414→async fn clone_project(
415→    State(state): State<SharedState>,
416→    Json(req): Json<CloneProjectRequest>,
417→) -> Result<impl IntoResponse, ApiError> {
418→    let repo_url = req.repo_url.trim().to_string();
419→
420→    // Parse repo name from URL (handles https://github.com/user/repo, user/repo, etc.)
421→    let repo_name = repo_url
422→        .trim_end_matches('/')
423→        .trim_end_matches(".git")
424→        .rsplit('/')
425→        .next()
426→        .ok_or_else(|| ApiError::BadRequest("Invalid repository URL".to_string()))?
427→        .to_string();
428→
429→    if repo_name.is_empty() {
430→        return Err(ApiError::BadRequest(
431→            "Could not parse repository name from URL".to_string(),
432→        ));
433→    }
434→
435→    // Normalize: if it looks like "user/repo", prepend GitHub URL
436→    let clone_url = if repo_url.starts_with("http://")
437→        || repo_url.starts_with("https://")
438→        || repo_url.starts_with("git@")
439→    {
440→        repo_url.clone()
441→    } else {
442→        format!("https://github.com/{}", repo_url)
443→    };
444→
445→    // If we have a GitHub token, use it for cloning (enables private repos)
446→    let (clone_url, token) = {
447→        let gh_token = state
448→            .github_token
449→            .lock()
450→            .map_err(|_| ApiError::from(FactoryError::LockPoisoned))?;
451→        if let Some(ref t) = *gh_token {
452→            if clone_url.starts_with("https://github.com/") {
453→                (
454→                    clone_url.replacen(
455→                        "https://github.com/",
456→                        &format!("https://x-access-token:{}@github.com/", t),
457→                        1,
458→                    ),
459→                    Some(t.clone()),
460→                )
461→            } else {
462→                (clone_url, Some(t.clone()))
463→            }
464→        } else {
465→            (clone_url, None)
466→        }
467→    };
468→
469→    // Clone into .forge/repos/<repo_name>
470→    let repos_dir = std::path::PathBuf::from(".forge/repos");
471→    tokio::fs::create_dir_all(&repos_dir)
472→        .await
473→        .map_err(|e| ApiError::Internal(format!("Failed to create repos directory: {}", e)))?;
474→
475→    let clone_path = repos_dir.join(&repo_name);
476→    let already_cloned = clone_path.exists();
477→
478→    if !already_cloned {
479→        let clone_path_str = clone_path.to_string_lossy().to_string();
480→
481→        // Run git clone asynchronously
482→        let output = tokio::process::Command::new("git")
483→            .args(["clone", &clone_url, &clone_path_str])
484→            .output()
485→            .await
486→            .map_err(|e| ApiError::Internal(format!("Failed to run git clone: {}", e)))?;
487→
488→        if !output.status.success() {
489→            let stderr = String::from_utf8_lossy(&output.stderr);
490→            let sanitized_stderr = if let Some(ref t) = token {
491→                stderr.trim().replace(t, "***")
492→            } else {
493→                stderr.trim().to_string()
494→            };
495→            return Err(ApiError::BadRequest(format!(
496→                "git clone failed: {}",
497→                sanitized_stderr
498→            )));
499→        }
500→
501→        // After successful clone, strip token from remote URL to prevent leaking
502→        if token.is_some() {
503→            let _ = tokio::process::Command::new("git")
504→                .args(["remote", "set-url", "origin", &repo_url])
505→                .current_dir(&clone_path_str)
506→                .output()
507→                .await;
508→        }
509→    }
510→
511→    // Resolve to absolute path for the project record
512→    let abs_path = tokio::fs::canonicalize(&clone_path)
513→        .await
514→        .map_err(|e| ApiError::Internal(format!("Failed to resolve path: {}", e)))?;
515→    let abs_path_str = abs_path.to_string_lossy().to_string();
516→
517→    // Parse the GitHub owner/repo from the original URL (before token injection)
518→    let github_repo = parse_github_owner_repo(&repo_url);
519→
520→    let repo_name_clone = repo_name.clone();
521→    let abs_path_clone = abs_path_str.clone();
522→    let github_repo_clone = github_repo.clone();
523→    let project = state
524→        .db
525→        .call(move |db| {
526→            // Check if a project already exists for this path
527→            let existing = db
528→                .list_projects()?
529→                .into_iter()
530→                .find(|p| p.path == abs_path_clone);
531→
532→            let project = if let Some(project) = existing {
533→                project
534→            } else {
535→                db.create_project(&repo_name_clone, &abs_path_clone)?
536→            };
537→
538→            // Store the GitHub owner/repo
539→            let project = if let Some(ref owner_repo) = github_repo_clone {
540→                db.update_project_github_repo(project.id, owner_repo)?
541→            } else {
542→                project
543→            };
544→            Ok(project)
545→        })
546→        .await
547→        .map_err(|e| ApiError::Internal(e.to_string()))?;
548→
549→    broadcast_message(
550→        &state.ws_tx,
551→        &WsMessage::ProjectCreated {
552→            project: project.clone(),
553→        },
554→    );
555→
556→    // Auto-sync GitHub issues in the background
557→    if github_repo.is_some() {
558→        let state_clone = Arc::clone(&state);
559→        let pid = project.id;
560→        tokio::spawn(async move {
561→            tokio::time::sleep(std::time::Duration::from_millis(500)).await;
562→            match do_sync_github_issues(&state_clone, pid).await {
563→                Ok(result) => {
564→                    eprintln!(
565→                        "Auto-synced {} GitHub issues for project {}",
566→                        result.imported, pid
567→                    );
568→                }
569→                Err(_) => {
570→                    eprintln!("Auto-sync GitHub issues failed for project {}", pid);
571→                }
572→            }
573→        });
574→    }
575→
576→    Ok((StatusCode::CREATED, Json(project)))
577→}
