  1→/** Unified state hook for the Mission Control dashboard — aggregates all projects into a single view. */
  2→import { useState, useEffect, useCallback, useRef, useMemo } from 'react';
  3→import { api } from '../api/client';
  4→import { useWsSubscribe } from '../contexts/WebSocketContext';
  5→import type {
  6→  Project,
  7→  Issue,
  8→  PipelineRun,
  9→  PipelinePhase,
 10→  AgentRunCard,
 11→  EventLogEntry,
 12→  WsMessage,
 13→  RunStatusFilter,
 14→  AgentTeamDetail,
 15→  AgentEvent,
 16→} from '../types';
 17→
 18→/** Internal state shape for the Mission Control hook */
 19→interface MissionControlState {
 20→  projects: Project[];
 21→  runs: Map<number, PipelineRun>;
 22→  issues: Map<number, Issue>;
 23→  phases: Map<number, PipelinePhase[]>;
 24→  agentTeams: Map<number, AgentTeamDetail>;
 25→  agentEvents: Map<number, AgentEvent[]>;
 26→  eventLog: EventLogEntry[];
 27→  loading: boolean;
 28→  error: string | null;
 29→}
 30→
 31→/** Return type of the useMissionControl hook */
 32→export interface MissionControlReturn {
 33→  /** All loaded projects */
 34→  projects: Project[];
 35→  /** Filtered and sorted agent run cards for the grid */
 36→  agentRunCards: AgentRunCard[];
 37→  /** Run counts by status */
 38→  statusCounts: Record<RunStatusFilter, number>;
 39→  /** Chronological event log entries */
 40→  eventLog: EventLogEntry[];
 41→  /** Pipeline phases by run ID */
 42→  phases: Map<number, PipelinePhase[]>;
 43→  /** Agent team details by run ID */
 44→  agentTeams: Map<number, AgentTeamDetail>;
 45→  /** Agent events by task ID */
 46→  agentEvents: Map<number, AgentEvent[]>;
 47→  /** Whether initial data is still loading */
 48→  loading: boolean;
 49→  /** Error message from initial load, or null */
 50→  error: string | null;
 51→  /** Currently selected project ID filter, or null for all */
 52→  selectedProjectId: number | null;
 53→  /** Set the project filter */
 54→  setSelectedProjectId: (id: number | null) => void;
 55→  /** Current status filter */
 56→  statusFilter: RunStatusFilter;
 57→  /** Set the status filter */
 58→  setStatusFilter: (filter: RunStatusFilter) => void;
 59→  /** Trigger a pipeline run for an issue */
 60→  triggerPipeline: (issueId: number) => Promise<void>;
 61→  /** Cancel a running pipeline */
 62→  cancelPipeline: (runId: number) => Promise<void>;
 63→  /** Create a new issue in a project */
 64→  createIssue: (projectId: number, title: string, description: string) => Promise<Issue>;
 65→  /** Create a new project */
 66→  createProject: (name: string, path: string) => Promise<Project>;
 67→  /** Clone a project from a repository URL */
 68→  cloneProject: (repoUrl: string) => Promise<Project>;
 69→  /** Delete a project and all its data */
 70→  deleteProject: (projectId: number) => Promise<void>;
 71→  /** Refresh all data from the server */
 72→  refresh: () => Promise<void>;
 73→  /** Issue counts grouped by project ID */
 74→  issuesByProject: Map<number, number>;
 75→}
 76→
 77→/** Status sort order: running first, then queued, failed, completed, cancelled */
 78→const STATUS_ORDER: Record<string, number> = {
 79→  running: 0,
 80→  queued: 1,
 81→  failed: 2,
 82→  completed: 3,
 83→  cancelled: 4,
 84→};
 85→
 86→/**
 87→ * Primary data hook for the Mission Control dashboard.
 88→ * Aggregates data from all projects, handles WebSocket updates,
 89→ * and provides filtering and actions.
 90→ */
 91→export default function useMissionControl(): MissionControlReturn {
 92→  const [state, setState] = useState<MissionControlState>({
 93→    projects: [],
 94→    runs: new Map(),
 95→    issues: new Map(),
 96→    phases: new Map(),
 97→    agentTeams: new Map(),
 98→    agentEvents: new Map(),
 99→    eventLog: [],
100→    loading: true,
101→    error: null,
102→  });
103→
104→  const [selectedProjectId, setSelectedProjectId] = useState<number | null>(null);
105→  const [statusFilter, setStatusFilter] = useState<RunStatusFilter>('all');
106→  const eventIdRef = useRef(0);
107→  const mountedRef = useRef(true);
108→
109→  /** Add an event log entry, capping at 500 entries */
110→  const addLogEntry = useCallback((
111→    source: EventLogEntry['source'],
112→    message: string,
113→    projectName?: string,
114→    runId?: number,
115→  ) => {
116→    setState(prev => ({
117→      ...prev,
118→      eventLog: [
119→        ...prev.eventLog.slice(-499),
120→        {
121→          id: String(++eventIdRef.current),
122→          timestamp: new Date().toISOString(),
123→          source,
124→          message,
125→          projectName,
126→          runId,
127→        },
128→      ],
129→    }));
130→  }, []);
131→
132→  // Load all projects and their active runs on mount
133→  useEffect(() => {
134→    mountedRef.current = true;
135→    let cancelled = false;
136→
137→    async function loadAll() {
138→      try {
139→        const projects = await api.listProjects();
140→        if (cancelled) return;
141→
142→        const issueMap = new Map<number, Issue>();
143→        const runMap = new Map<number, PipelineRun>();
144→        const phaseMap = new Map<number, PipelinePhase[]>();
145→
146→        for (const project of projects) {
147→          try {
148→            const board = await api.getBoard(project.id);
149→            if (cancelled) return;
150→            for (const col of board.columns) {
151→              for (const item of col.issues) {
152→                issueMap.set(item.issue.id, item.issue);
153→                if (item.active_run) {
154→                  runMap.set(item.active_run.id, item.active_run);
155→                }
156→              }
157→            }
158→          } catch {
159→            // Skip projects that fail to load
160→          }
161→        }
162→
163→        if (!cancelled) {
164→          setState(prev => ({
165→            ...prev,
166→            projects,
167→            issues: issueMap,
168→            runs: runMap,
169→            phases: phaseMap,
170→            loading: false,
171→          }));
172→          addLogEntry('system', `Loaded ${projects.length} projects, ${runMap.size} active runs`);
173→        }
174→      } catch (err) {
175→        if (!cancelled) {
176→          setState(prev => ({
177→            ...prev,
178→            loading: false,
179→            error: err instanceof Error ? err.message : 'Failed to load',
180→          }));
181→        }
182→      }
183→    }
184→
185→    loadAll();
186→    return () => { cancelled = true; mountedRef.current = false; };
187→  }, [addLogEntry]);
188→
189→  // WebSocket message handler — uses a ref for issues to avoid stale closure
190→  const issuesRef = useRef(state.issues);
191→  issuesRef.current = state.issues;
192→
193→  useWsSubscribe(useCallback((msg: WsMessage) => {
194→    if (!mountedRef.current) return;
195→
196→    switch (msg.type) {
197→      case 'PipelineStarted': {
198→        const run = msg.data.run;
199→        setState(prev => {
200→          const newRuns = new Map(prev.runs);
201→          newRuns.set(run.id, run);
202→          return { ...prev, runs: newRuns };
203→        });
204→        const issue = issuesRef.current.get(run.issue_id);
205→        addLogEntry('system', `Pipeline started for "${issue?.title ?? `issue #${run.issue_id}`}"`, undefined, run.id);
206→        break;
207→      }
208→
209→      case 'PipelineProgress': {
210→        const { run_id, phase, iteration } = msg.data;
211→        setState(prev => {
212→          const newRuns = new Map(prev.runs);
213→          const existing = newRuns.get(run_id);
214→          if (existing) {
215→            newRuns.set(run_id, { ...existing, current_phase: phase, iteration });
216→          }
217→          return { ...prev, runs: newRuns };
218→        });
219→        break;
220→      }
221→
222→      case 'PipelineCompleted': {
223→        const run = msg.data.run;
224→        setState(prev => {
225→          const newRuns = new Map(prev.runs);
226→          newRuns.set(run.id, run);
227→          return { ...prev, runs: newRuns };
228→        });
229→        addLogEntry('system', 'Pipeline completed successfully', undefined, run.id);
230→        break;
231→      }
232→
233→      case 'PipelineFailed': {
234→        const run = msg.data.run;
235→        setState(prev => {
236→          const newRuns = new Map(prev.runs);
237→          newRuns.set(run.id, run);
238→          return { ...prev, runs: newRuns };
239→        });
240→        addLogEntry('error', `Pipeline failed: ${run.error ?? 'unknown error'}`, undefined, run.id);
241→        break;
242→      }
243→
244→      case 'PipelinePhaseStarted': {
245→        const { run_id, phase_number, phase_name } = msg.data;
246→        setState(prev => {
247→          const newPhases = new Map(prev.phases);
248→          const existing = newPhases.get(run_id) ?? [];
249→          const newPhase: PipelinePhase = {
250→            id: 0,
251→            run_id,
252→            phase_number,
253→            phase_name,
254→            status: 'running',
255→            iteration: null,
256→            budget: null,
257→            started_at: new Date().toISOString(),
258→            completed_at: null,
259→            error: null,
260→          };
261→          newPhases.set(run_id, [...existing, newPhase]);
262→          return { ...prev, phases: newPhases };
263→        });
264→        addLogEntry('phase', `Phase "${phase_name}" started`, undefined, run_id);
265→        break;
266→      }
267→
268→      case 'PipelinePhaseCompleted': {
269→        const { run_id, phase_number, success } = msg.data;
270→        setState(prev => {
271→          const newPhases = new Map(prev.phases);
272→          const existing = newPhases.get(run_id) ?? [];
273→          newPhases.set(run_id, existing.map(p =>
274→            p.phase_number === phase_number
275→              ? { ...p, status: success ? 'completed' : 'failed', completed_at: new Date().toISOString() }
276→              : p
277→          ));
278→          return { ...prev, phases: newPhases };
279→        });
280→        addLogEntry('phase', `Phase completed (${success ? 'success' : 'failed'})`, undefined, run_id);
281→        break;
282→      }
283→
284→      case 'PipelineReviewStarted': {
285→        addLogEntry('review', 'Review started', undefined, msg.data.run_id);
286→        break;
287→      }
288→
289→      case 'PipelineReviewCompleted': {
290→        const { passed, findings_count } = msg.data;
291→        addLogEntry('review', `Review ${passed ? 'passed' : `failed (${findings_count} findings)`}`, undefined, msg.data.run_id);
292→        break;
293→      }
294→
295→      case 'PipelineBranchCreated': {
296→        const { run_id, branch_name } = msg.data;
297→        setState(prev => {
298→          const newRuns = new Map(prev.runs);
299→          const existing = newRuns.get(run_id);
300→          if (existing) {
301→            newRuns.set(run_id, { ...existing, branch_name });
302→          }
303→          return { ...prev, runs: newRuns };
304→        });
305→        addLogEntry('git', `Branch created: ${branch_name}`, undefined, run_id);
306→        break;
307→      }
308→
309→      case 'PipelinePrCreated': {
310→        const { run_id, pr_url } = msg.data;
311→        setState(prev => {
312→          const newRuns = new Map(prev.runs);
313→          const existing = newRuns.get(run_id);
314→          if (existing) {
315→            newRuns.set(run_id, { ...existing, pr_url });
316→          }
317→          return { ...prev, runs: newRuns };
318→        });
319→        addLogEntry('git', 'PR created', undefined, run_id);
320→        break;
321→      }
322→
323→      case 'TeamCreated': {
324→        const { run_id, team_id, strategy, isolation, plan_summary, tasks } = msg.data;
325→        setState(prev => {
326→          const newTeams = new Map(prev.agentTeams);
327→          newTeams.set(run_id, {
328→            team: { id: team_id, run_id, strategy, isolation, plan_summary, created_at: new Date().toISOString() },
329→            tasks: tasks ?? [],
330→          });
331→          return { ...prev, agentTeams: newTeams };
332→        });
333→        addLogEntry('agent', `Agent team created (${strategy})`, undefined, run_id);
334→        break;
335→      }
336→
337→      case 'AgentTaskStarted': {
338→        addLogEntry('agent', `Task "${msg.data.name}" started (${msg.data.role})`, undefined, undefined);
339→        break;
340→      }
341→
342→      case 'AgentThinking':
343→      case 'AgentAction':
344→      case 'AgentOutput':
345→      case 'AgentSignal': {
346→        const taskId = msg.data.task_id;
347→        setState(prev => {
348→          const newEvents = new Map(prev.agentEvents);
349→          const taskEvents = newEvents.get(taskId) ?? [];
350→          const event: AgentEvent = {
351→            id: taskEvents.length + 1,
352→            task_id: taskId,
353→            event_type: msg.type === 'AgentThinking' ? 'thinking'
354→              : msg.type === 'AgentAction' ? 'action'
355→              : msg.type === 'AgentOutput' ? 'output'
356→              : 'signal',
357→            content: msg.type === 'AgentAction' ? msg.data.summary : msg.data.content,
358→            metadata: msg.type === 'AgentAction' ? msg.data.metadata : null,
359→            created_at: new Date().toISOString(),
360→          };
361→          newEvents.set(taskId, [...taskEvents.slice(-199), event]);
362→          return { ...prev, agentEvents: newEvents };
363→        });
364→        break;
365→      }
366→
367→      case 'IssueCreated': {
368→        const issue = msg.data.issue;
369→        setState(prev => {
370→          const newIssues = new Map(prev.issues);
371→          newIssues.set(issue.id, issue);
372→          return { ...prev, issues: newIssues };
373→        });
374→        addLogEntry('system', `Issue created: "${issue.title}"`);
375→        break;
376→      }
377→
378→      case 'IssueDeleted': {
379→        setState(prev => {
380→          const newIssues = new Map(prev.issues);
381→          newIssues.delete(msg.data.issue_id);
382→          return { ...prev, issues: newIssues };
383→        });
384→        break;
385→      }
386→
387→      case 'ProjectCreated': {
388→        const project = msg.data.project;
389→        setState(prev => {
390→          if (prev.projects.some(p => p.id === project.id)) return prev;
391→          return { ...prev, projects: [...prev.projects, project] };
392→        });
393→        addLogEntry('system', `Project added: "${project.name}"`);
394→        break;
395→      }
396→
397→      case 'ProjectDeleted': {
398→        const deletedId = msg.data.project_id;
399→        setState(prev => {
400→          const newProjects = prev.projects.filter(p => p.id !== deletedId);
401→          const newIssues = new Map(prev.issues);
402→          const newRuns = new Map(prev.runs);
403→          // Remove issues belonging to the deleted project
404→          for (const [id, issue] of newIssues) {
405→            if (issue.project_id === deletedId) {
406→              // Also remove runs for this issue
407→              for (const [runId, run] of newRuns) {
408→                if (run.issue_id === id) newRuns.delete(runId);
409→              }
410→              newIssues.delete(id);
411→            }
412→          }
413→          return { ...prev, projects: newProjects, issues: newIssues, runs: newRuns };
414→        });
415→        addLogEntry('system', 'Project deleted');
416→        break;
417→      }
418→    }
419→  }, [addLogEntry]));
420→
421→  // Compute filtered and sorted agent run cards
422→  const agentRunCards: AgentRunCard[] = useMemo(() => {
423→    return Array.from(state.runs.values())
424→      .filter(run => {
425→        if (selectedProjectId !== null) {
426→          const issue = state.issues.get(run.issue_id);
427→          if (issue && issue.project_id !== selectedProjectId) return false;
428→        }
429→        if (statusFilter !== 'all' && run.status !== statusFilter) return false;
430→        return true;
431→      })
432→      .sort((a, b) => {
433→        const diff = (STATUS_ORDER[a.status] ?? 5) - (STATUS_ORDER[b.status] ?? 5);
434→        if (diff !== 0) return diff;
435→        return new Date(b.started_at).getTime() - new Date(a.started_at).getTime();
436→      })
437→      .map(run => ({
438→        run,
439→        issue: state.issues.get(run.issue_id) ?? {
440→          id: run.issue_id,
441→          project_id: 0,
442→          title: `Issue #${run.issue_id}`,
443→          description: '',
444→          column: 'backlog' as const,
445→          position: 0,
446→          priority: 'medium' as const,
447→          labels: [],
448→          github_issue_number: null,
449→          created_at: '',
450→          updated_at: '',
451→        },
452→        project: state.projects.find(p => {
453→          const issue = state.issues.get(run.issue_id);
454→          return issue && p.id === issue.project_id;
455→        }) ?? { id: 0, name: 'Unknown', path: '', github_repo: null, created_at: '' },
456→      }));
457→  }, [state.runs, state.issues, state.projects, selectedProjectId, statusFilter]);
458→
459→  // Compute status counts (unfiltered — always reflect total state)
460→  const statusCounts: Record<RunStatusFilter, number> = useMemo(() => {
461→    const runs = Array.from(state.runs.values());
462→    return {
463→      all: runs.length,
464→      running: runs.filter(r => r.status === 'running').length,
465→      queued: runs.filter(r => r.status === 'queued').length,
466→      completed: runs.filter(r => r.status === 'completed').length,
467→      failed: runs.filter(r => r.status === 'failed').length,
468→    };
469→  }, [state.runs]);
470→
471→  // Actions
472→  const triggerPipeline = useCallback(async (issueId: number) => {
473→    const run = await api.triggerPipeline(issueId);
474→    setState(prev => {
475→      const newRuns = new Map(prev.runs);
476→      newRuns.set(run.id, run);
477→      return { ...prev, runs: newRuns };
478→    });
479→  }, []);
480→
481→  const cancelPipeline = useCallback(async (runId: number) => {
482→    const run = await api.cancelPipelineRun(runId);
483→    setState(prev => {
484→      const newRuns = new Map(prev.runs);
485→      newRuns.set(run.id, run);
486→      return { ...prev, runs: newRuns };
487→    });
488→  }, []);
489→
490→  const createIssue = useCallback(async (projectId: number, title: string, description: string) => {
491→    const issue = await api.createIssue(projectId, title, description);
492→    setState(prev => {
493→      const newIssues = new Map(prev.issues);
494→      newIssues.set(issue.id, issue);
495→      return { ...prev, issues: newIssues };
496→    });
497→    return issue;
498→  }, []);
499→
500→  const createProject = useCallback(async (name: string, path: string) => {
501→    const project = await api.createProject(name, path);
502→    setState(prev => ({
503→      ...prev,
504→      projects: [...prev.projects, project],
505→    }));
506→    return project;
507→  }, []);
508→
509→  const cloneProject = useCallback(async (repoUrl: string) => {
510→    const project = await api.cloneProject(repoUrl);
511→    setState(prev => ({
512→      ...prev,
513→      projects: [...prev.projects, project],
514→    }));
515→    return project;
516→  }, []);
517→
518→  const deleteProject = useCallback(async (projectId: number) => {
519→    await api.deleteProject(projectId);
520→    // Optimistic removal — WS message will also trigger state cleanup
521→    setState(prev => ({
522→      ...prev,
523→      projects: prev.projects.filter(p => p.id !== projectId),
524→    }));
525→  }, []);
526→
527→  const refresh = useCallback(async () => {
528→    setState(prev => ({ ...prev, loading: true }));
529→    try {
530→      const projects = await api.listProjects();
531→      const issueMap = new Map<number, Issue>();
532→      const runMap = new Map<number, PipelineRun>();
533→      for (const project of projects) {
534→        try {
535→          const board = await api.getBoard(project.id);
536→          for (const col of board.columns) {
537→            for (const item of col.issues) {
538→              issueMap.set(item.issue.id, item.issue);
539→              if (item.active_run) {
540→                runMap.set(item.active_run.id, item.active_run);
541→              }
542→            }
543→          }
544→        } catch { /* skip */ }
545→      }
546→      setState(prev => ({
547→        ...prev,
548→        projects,
549→        issues: issueMap,
550→        runs: runMap,
551→        loading: false,
552→        error: null,
553→      }));
554→    } catch (err) {
555→      setState(prev => ({
556→        ...prev,
557→        loading: false,
558→        error: err instanceof Error ? err.message : 'Refresh failed',
559→      }));
560→    }
561→  }, []);
562→
563→  // Compute issue counts grouped by project ID
564→  const issuesByProject = useMemo(() => {
565→    const map = new Map<number, number>();
566→    for (const issue of state.issues.values()) {
567→      map.set(issue.project_id, (map.get(issue.project_id) ?? 0) + 1);
568→    }
569→    return map;
570→  }, [state.issues]);
571→
572→  return {
573→    projects: state.projects,
574→    agentRunCards,
575→    statusCounts,
576→    eventLog: state.eventLog,
577→    phases: state.phases,
578→    agentTeams: state.agentTeams,
579→    agentEvents: state.agentEvents,
580→    loading: state.loading,
581→    error: state.error,
582→    selectedProjectId,
583→    setSelectedProjectId,
584→    statusFilter,
585→    setStatusFilter,
586→    triggerPipeline,
587→    cancelPipeline,
588→    createIssue,
589→    createProject,
590→    cloneProject,
591→    deleteProject,
592→    refresh,
593→    issuesByProject,
594→  };
595→}
