/** Unified state hook for the Mission Control dashboard — aggregates all projects into a single view. */
import { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { api } from '../api/client';
import { useWsSubscribe } from '../contexts/WebSocketContext';
import type {
  Project,
  Issue,
  PipelineRun,
  PipelinePhase,
  AgentRunCard,
  EventLogEntry,
  WsMessage,
  RunStatusFilter,
  AgentTeamDetail,
  AgentEvent,
} from '../types';

/** Internal state shape for the Mission Control hook */
interface MissionControlState {
  projects: Project[];
  runs: Map<number, PipelineRun>;
  issues: Map<number, Issue>;
  phases: Map<number, PipelinePhase[]>;
  agentTeams: Map<number, AgentTeamDetail>;
  agentEvents: Map<number, AgentEvent[]>;
  eventLog: EventLogEntry[];
  loading: boolean;
  error: string | null;
}

/** An idle issue card — issue without an active pipeline run */
export interface IdleIssueCard {
  issue: Issue;
  project: Project;
}

/** Return type of the useMissionControl hook */
export interface MissionControlReturn {
  /** All loaded projects */
  projects: Project[];
  /** Filtered and sorted agent run cards for the grid */
  agentRunCards: AgentRunCard[];
  /** Issues without active pipeline runs, available to start */
  idleIssueCards: IdleIssueCard[];
  /** Run counts by status */
  statusCounts: Record<RunStatusFilter, number>;
  /** Chronological event log entries */
  eventLog: EventLogEntry[];
  /** Pipeline phases by run ID */
  phases: Map<number, PipelinePhase[]>;
  /** Agent team details by run ID */
  agentTeams: Map<number, AgentTeamDetail>;
  /** Agent events by task ID */
  agentEvents: Map<number, AgentEvent[]>;
  /** Whether initial data is still loading */
  loading: boolean;
  /** Error message from initial load, or null */
  error: string | null;
  /** Currently selected project ID filter, or null for all */
  selectedProjectId: number | null;
  /** Set the project filter */
  setSelectedProjectId: (id: number | null) => void;
  /** Current status filter */
  statusFilter: RunStatusFilter;
  /** Set the status filter */
  setStatusFilter: (filter: RunStatusFilter) => void;
  /** Trigger a pipeline run for an issue */
  triggerPipeline: (issueId: number) => Promise<void>;
  /** Cancel a running pipeline */
  cancelPipeline: (runId: number) => Promise<void>;
  /** Create a new issue in a project */
  createIssue: (projectId: number, title: string, description: string) => Promise<Issue>;
  /** Create a new project */
  createProject: (name: string, path: string) => Promise<Project>;
  /** Clone a project from a repository URL */
  cloneProject: (repoUrl: string) => Promise<Project>;
  /** Delete a project and all its data */
  deleteProject: (projectId: number) => Promise<void>;
  /** Refresh all data from the server */
  refresh: () => Promise<void>;
  /** Issue counts grouped by project ID */
  issuesByProject: Map<number, number>;
}

/** Status sort order: running first, then queued, failed, completed, cancelled */
const STATUS_ORDER: Record<string, number> = {
  running: 0,
  queued: 1,
  failed: 2,
  completed: 3,
  cancelled: 4,
};

/**
 * Primary data hook for the Mission Control dashboard.
 * Aggregates data from all projects, handles WebSocket updates,
 * and provides filtering and actions.
 */
export default function useMissionControl(): MissionControlReturn {
  const [state, setState] = useState<MissionControlState>({
    projects: [],
    runs: new Map(),
    issues: new Map(),
    phases: new Map(),
    agentTeams: new Map(),
    agentEvents: new Map(),
    eventLog: [],
    loading: true,
    error: null,
  });

  const [selectedProjectId, setSelectedProjectId] = useState<number | null>(null);
  const [statusFilter, setStatusFilter] = useState<RunStatusFilter>('all');
  const eventIdRef = useRef(0);
  const mountedRef = useRef(true);

  /** Add an event log entry, capping at 500 entries */
  const addLogEntry = useCallback((
    source: EventLogEntry['source'],
    message: string,
    projectName?: string,
    runId?: number,
  ) => {
    setState(prev => ({
      ...prev,
      eventLog: [
        ...prev.eventLog.slice(-499),
        {
          id: String(++eventIdRef.current),
          timestamp: new Date().toISOString(),
          source,
          message,
          projectName,
          runId,
        },
      ],
    }));
  }, []);

  // Load all projects and their active runs on mount
  useEffect(() => {
    mountedRef.current = true;
    let cancelled = false;

    async function loadAll() {
      try {
        const projects = await api.listProjects();
        if (cancelled) return;

        const issueMap = new Map<number, Issue>();
        const runMap = new Map<number, PipelineRun>();
        const phaseMap = new Map<number, PipelinePhase[]>();

        for (const project of projects) {
          try {
            const board = await api.getBoard(project.id);
            if (cancelled) return;
            for (const col of board.columns) {
              for (const item of col.issues) {
                issueMap.set(item.issue.id, item.issue);
                if (item.active_run) {
                  runMap.set(item.active_run.id, item.active_run);
                }
              }
            }
          } catch {
            // Skip projects that fail to load
          }
        }

        if (!cancelled) {
          setState(prev => ({
            ...prev,
            projects,
            issues: issueMap,
            runs: runMap,
            phases: phaseMap,
            loading: false,
          }));
          addLogEntry('system', `Loaded ${projects.length} projects, ${runMap.size} active runs`);
        }
      } catch (err) {
        if (!cancelled) {
          setState(prev => ({
            ...prev,
            loading: false,
            error: err instanceof Error ? err.message : 'Failed to load',
          }));
        }
      }
    }

    loadAll();
    return () => { cancelled = true; mountedRef.current = false; };
  }, [addLogEntry]);

  // WebSocket message handler — uses a ref for issues to avoid stale closure
  const issuesRef = useRef(state.issues);
  issuesRef.current = state.issues;

  useWsSubscribe(useCallback((msg: WsMessage) => {
    if (!mountedRef.current) return;

    switch (msg.type) {
      case 'PipelineStarted': {
        const run = msg.data.run;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          newRuns.set(run.id, run);
          return { ...prev, runs: newRuns };
        });
        const issue = issuesRef.current.get(run.issue_id);
        addLogEntry('system', `Pipeline started for "${issue?.title ?? `issue #${run.issue_id}`}"`, undefined, run.id);
        break;
      }

      case 'PipelineProgress': {
        const { run_id, phase, iteration } = msg.data;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          const existing = newRuns.get(run_id);
          if (existing) {
            newRuns.set(run_id, { ...existing, current_phase: phase, iteration });
          }
          return { ...prev, runs: newRuns };
        });
        break;
      }

      case 'PipelineCompleted': {
        const run = msg.data.run;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          newRuns.set(run.id, run);
          return { ...prev, runs: newRuns };
        });
        addLogEntry('system', 'Pipeline completed successfully', undefined, run.id);
        break;
      }

      case 'PipelineFailed': {
        const run = msg.data.run;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          newRuns.set(run.id, run);
          return { ...prev, runs: newRuns };
        });
        addLogEntry('error', `Pipeline failed: ${run.error ?? 'unknown error'}`, undefined, run.id);
        break;
      }

      case 'PipelinePhaseStarted': {
        const { run_id, phase_number, phase_name } = msg.data;
        setState(prev => {
          const newPhases = new Map(prev.phases);
          const existing = newPhases.get(run_id) ?? [];
          const newPhase: PipelinePhase = {
            id: 0,
            run_id,
            phase_number,
            phase_name,
            status: 'running',
            iteration: null,
            budget: null,
            started_at: new Date().toISOString(),
            completed_at: null,
            error: null,
          };
          newPhases.set(run_id, [...existing, newPhase]);
          return { ...prev, phases: newPhases };
        });
        addLogEntry('phase', `Phase "${phase_name}" started`, undefined, run_id);
        break;
      }

      case 'PipelinePhaseCompleted': {
        const { run_id, phase_number, success } = msg.data;
        setState(prev => {
          const newPhases = new Map(prev.phases);
          const existing = newPhases.get(run_id) ?? [];
          newPhases.set(run_id, existing.map(p =>
            p.phase_number === phase_number
              ? { ...p, status: success ? 'completed' : 'failed', completed_at: new Date().toISOString() }
              : p
          ));
          return { ...prev, phases: newPhases };
        });
        addLogEntry('phase', `Phase completed (${success ? 'success' : 'failed'})`, undefined, run_id);
        break;
      }

      case 'PipelineReviewStarted': {
        addLogEntry('review', 'Review started', undefined, msg.data.run_id);
        break;
      }

      case 'PipelineReviewCompleted': {
        const { passed, findings_count } = msg.data;
        addLogEntry('review', `Review ${passed ? 'passed' : `failed (${findings_count} findings)`}`, undefined, msg.data.run_id);
        break;
      }

      case 'PipelineBranchCreated': {
        const { run_id, branch_name } = msg.data;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          const existing = newRuns.get(run_id);
          if (existing) {
            newRuns.set(run_id, { ...existing, branch_name });
          }
          return { ...prev, runs: newRuns };
        });
        addLogEntry('git', `Branch created: ${branch_name}`, undefined, run_id);
        break;
      }

      case 'PipelinePrCreated': {
        const { run_id, pr_url } = msg.data;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          const existing = newRuns.get(run_id);
          if (existing) {
            newRuns.set(run_id, { ...existing, pr_url });
          }
          return { ...prev, runs: newRuns };
        });
        addLogEntry('git', 'PR created', undefined, run_id);
        break;
      }

      case 'TeamCreated': {
        const { run_id, team_id, strategy, isolation, plan_summary, tasks } = msg.data;
        setState(prev => {
          const newTeams = new Map(prev.agentTeams);
          newTeams.set(run_id, {
            team: { id: team_id, run_id, strategy, isolation, plan_summary, created_at: new Date().toISOString() },
            tasks: tasks ?? [],
          });
          return { ...prev, agentTeams: newTeams };
        });
        addLogEntry('agent', `Agent team created (${strategy})`, undefined, run_id);
        break;
      }

      case 'AgentTaskStarted': {
        addLogEntry('agent', `Task "${msg.data.name}" started (${msg.data.role})`, undefined, undefined);
        break;
      }

      case 'AgentThinking':
      case 'AgentAction':
      case 'AgentOutput':
      case 'AgentSignal': {
        const taskId = msg.data.task_id;
        setState(prev => {
          const newEvents = new Map(prev.agentEvents);
          const taskEvents = newEvents.get(taskId) ?? [];
          const event: AgentEvent = {
            id: taskEvents.length + 1,
            task_id: taskId,
            event_type: msg.type === 'AgentThinking' ? 'thinking'
              : msg.type === 'AgentAction' ? 'action'
              : msg.type === 'AgentOutput' ? 'output'
              : 'signal',
            content: msg.type === 'AgentAction' ? msg.data.summary : msg.data.content,
            metadata: msg.type === 'AgentAction' ? msg.data.metadata : null,
            created_at: new Date().toISOString(),
          };
          newEvents.set(taskId, [...taskEvents.slice(-199), event]);
          return { ...prev, agentEvents: newEvents };
        });
        break;
      }

      case 'IssueCreated': {
        const issue = msg.data.issue;
        setState(prev => {
          const newIssues = new Map(prev.issues);
          newIssues.set(issue.id, issue);
          return { ...prev, issues: newIssues };
        });
        addLogEntry('system', `Issue created: "${issue.title}"`);
        break;
      }

      case 'IssueDeleted': {
        setState(prev => {
          const newIssues = new Map(prev.issues);
          newIssues.delete(msg.data.issue_id);
          return { ...prev, issues: newIssues };
        });
        break;
      }

      case 'ProjectCreated': {
        const project = msg.data.project;
        setState(prev => {
          if (prev.projects.some(p => p.id === project.id)) return prev;
          return { ...prev, projects: [...prev.projects, project] };
        });
        addLogEntry('system', `Project added: "${project.name}"`);
        break;
      }

      case 'ProjectDeleted': {
        const deletedId = msg.data.project_id;
        setState(prev => {
          const newProjects = prev.projects.filter(p => p.id !== deletedId);
          const newIssues = new Map(prev.issues);
          const newRuns = new Map(prev.runs);
          // Remove issues belonging to the deleted project
          for (const [id, issue] of newIssues) {
            if (issue.project_id === deletedId) {
              // Also remove runs for this issue
              for (const [runId, run] of newRuns) {
                if (run.issue_id === id) newRuns.delete(runId);
              }
              newIssues.delete(id);
            }
          }
          return { ...prev, projects: newProjects, issues: newIssues, runs: newRuns };
        });
        addLogEntry('system', 'Project deleted');
        break;
      }
    }
  }, [addLogEntry]));

  // Compute filtered and sorted agent run cards
  const agentRunCards: AgentRunCard[] = useMemo(() => {
    return Array.from(state.runs.values())
      .filter(run => {
        if (selectedProjectId !== null) {
          const issue = state.issues.get(run.issue_id);
          if (issue && issue.project_id !== selectedProjectId) return false;
        }
        if (statusFilter !== 'all' && run.status !== statusFilter) return false;
        return true;
      })
      .sort((a, b) => {
        const diff = (STATUS_ORDER[a.status] ?? 5) - (STATUS_ORDER[b.status] ?? 5);
        if (diff !== 0) return diff;
        return new Date(b.started_at).getTime() - new Date(a.started_at).getTime();
      })
      .map(run => ({
        run,
        issue: state.issues.get(run.issue_id) ?? {
          id: run.issue_id,
          project_id: 0,
          title: `Issue #${run.issue_id}`,
          description: '',
          column: 'backlog' as const,
          position: 0,
          priority: 'medium' as const,
          labels: [],
          github_issue_number: null,
          created_at: '',
          updated_at: '',
        },
        project: state.projects.find(p => {
          const issue = state.issues.get(run.issue_id);
          return issue && p.id === issue.project_id;
        }) ?? { id: 0, name: 'Unknown', path: '', github_repo: null, created_at: '' },
      }));
  }, [state.runs, state.issues, state.projects, selectedProjectId, statusFilter]);

  // Compute status counts (unfiltered — always reflect total state)
  const statusCounts: Record<RunStatusFilter, number> = useMemo(() => {
    const runs = Array.from(state.runs.values());
    return {
      all: runs.length,
      running: runs.filter(r => r.status === 'running').length,
      queued: runs.filter(r => r.status === 'queued').length,
      completed: runs.filter(r => r.status === 'completed').length,
      failed: runs.filter(r => r.status === 'failed').length,
    };
  }, [state.runs]);

  // Actions
  const triggerPipeline = useCallback(async (issueId: number) => {
    const run = await api.triggerPipeline(issueId);
    setState(prev => {
      const newRuns = new Map(prev.runs);
      newRuns.set(run.id, run);
      return { ...prev, runs: newRuns };
    });
  }, []);

  const cancelPipeline = useCallback(async (runId: number) => {
    const run = await api.cancelPipelineRun(runId);
    setState(prev => {
      const newRuns = new Map(prev.runs);
      newRuns.set(run.id, run);
      return { ...prev, runs: newRuns };
    });
  }, []);

  const createIssue = useCallback(async (projectId: number, title: string, description: string) => {
    const issue = await api.createIssue(projectId, title, description);
    setState(prev => {
      const newIssues = new Map(prev.issues);
      newIssues.set(issue.id, issue);
      return { ...prev, issues: newIssues };
    });
    return issue;
  }, []);

  const createProject = useCallback(async (name: string, path: string) => {
    const project = await api.createProject(name, path);
    setState(prev => ({
      ...prev,
      projects: [...prev.projects, project],
    }));
    return project;
  }, []);

  const cloneProject = useCallback(async (repoUrl: string) => {
    const project = await api.cloneProject(repoUrl);
    setState(prev => ({
      ...prev,
      projects: [...prev.projects, project],
    }));
    return project;
  }, []);

  const deleteProject = useCallback(async (projectId: number) => {
    await api.deleteProject(projectId);
    // Optimistic removal — WS message will also trigger state cleanup
    setState(prev => ({
      ...prev,
      projects: prev.projects.filter(p => p.id !== projectId),
    }));
  }, []);

  const refresh = useCallback(async () => {
    setState(prev => ({ ...prev, loading: true }));
    try {
      const projects = await api.listProjects();
      const issueMap = new Map<number, Issue>();
      const runMap = new Map<number, PipelineRun>();
      for (const project of projects) {
        try {
          const board = await api.getBoard(project.id);
          for (const col of board.columns) {
            for (const item of col.issues) {
              issueMap.set(item.issue.id, item.issue);
              if (item.active_run) {
                runMap.set(item.active_run.id, item.active_run);
              }
            }
          }
        } catch { /* skip */ }
      }
      setState(prev => ({
        ...prev,
        projects,
        issues: issueMap,
        runs: runMap,
        loading: false,
        error: null,
      }));
    } catch (err) {
      setState(prev => ({
        ...prev,
        loading: false,
        error: err instanceof Error ? err.message : 'Refresh failed',
      }));
    }
  }, []);

  // Compute issue counts grouped by project ID
  const issuesByProject = useMemo(() => {
    const map = new Map<number, number>();
    for (const issue of state.issues.values()) {
      map.set(issue.project_id, (map.get(issue.project_id) ?? 0) + 1);
    }
    return map;
  }, [state.issues]);

  return {
    projects: state.projects,
    agentRunCards,
    statusCounts,
    eventLog: state.eventLog,
    phases: state.phases,
    agentTeams: state.agentTeams,
    agentEvents: state.agentEvents,
    loading: state.loading,
    error: state.error,
    selectedProjectId,
    setSelectedProjectId,
    statusFilter,
    setStatusFilter,
    triggerPipeline,
    cancelPipeline,
    createIssue,
    createProject,
    cloneProject,
    deleteProject,
    refresh,
    issuesByProject,
  };
}

/** Unified state hook for the Mission Control dashboard — aggregates all projects into a single view. */
import { useState, useEffect, useCallback, useRef, useMemo } from 'react';
import { api } from '../api/client';
import { useWsSubscribe } from '../contexts/WebSocketContext';
import type {
  Project,
  Issue,
  PipelineRun,
  PipelinePhase,
  AgentRunCard,
  EventLogEntry,
  WsMessage,
  RunStatusFilter,
  AgentTeamDetail,
  AgentEvent,
} from '../types';

/** Internal state shape for the Mission Control hook */
interface MissionControlState {
  projects: Project[];
  runs: Map<number, PipelineRun>;
  issues: Map<number, Issue>;
  phases: Map<number, PipelinePhase[]>;
  agentTeams: Map<number, AgentTeamDetail>;
  agentEvents: Map<number, AgentEvent[]>;
  eventLog: EventLogEntry[];
  loading: boolean;
  error: string | null;
}

/** An idle issue card — issue without an active pipeline run */
export interface IdleIssueCard {
  issue: Issue;
  project: Project;
}

/** Return type of the useMissionControl hook */
export interface MissionControlReturn {
  /** All loaded projects */
  projects: Project[];
  /** Filtered and sorted agent run cards for the grid */
  agentRunCards: AgentRunCard[];
  /** Issues without active pipeline runs, available to start */
  idleIssueCards: IdleIssueCard[];
  /** Run counts by status */
  statusCounts: Record<RunStatusFilter, number>;
  /** Chronological event log entries */
  eventLog: EventLogEntry[];
  /** Pipeline phases by run ID */
  phases: Map<number, PipelinePhase[]>;
  /** Agent team details by run ID */
  agentTeams: Map<number, AgentTeamDetail>;
  /** Agent events by task ID */
  agentEvents: Map<number, AgentEvent[]>;
  /** Whether initial data is still loading */
  loading: boolean;
  /** Error message from initial load, or null */
  error: string | null;
  /** Currently selected project ID filter, or null for all */
  selectedProjectId: number | null;
  /** Set the project filter */
  setSelectedProjectId: (id: number | null) => void;
  /** Current status filter */
  statusFilter: RunStatusFilter;
  /** Set the status filter */
  setStatusFilter: (filter: RunStatusFilter) => void;
  /** Trigger a pipeline run for an issue */
  triggerPipeline: (issueId: number) => Promise<void>;
  /** Cancel a running pipeline */
  cancelPipeline: (runId: number) => Promise<void>;
  /** Create a new issue in a project */
  createIssue: (projectId: number, title: string, description: string) => Promise<Issue>;
  /** Create a new project */
  createProject: (name: string, path: string) => Promise<Project>;
  /** Clone a project from a repository URL */
  cloneProject: (repoUrl: string) => Promise<Project>;
  /** Delete a project and all its data */
  deleteProject: (projectId: number) => Promise<void>;
  /** Refresh all data from the server */
  refresh: () => Promise<void>;
  /** Issue counts grouped by project ID */
  issuesByProject: Map<number, number>;
}

/** Status sort order: running first, then queued, failed, completed, cancelled */
const STATUS_ORDER: Record<string, number> = {
  running: 0,
  queued: 1,
  failed: 2,
  completed: 3,
  cancelled: 4,
};

/**
 * Primary data hook for the Mission Control dashboard.
 * Aggregates data from all projects, handles WebSocket updates,
 * and provides filtering and actions.
 */
export default function useMissionControl(): MissionControlReturn {
  const [state, setState] = useState<MissionControlState>({
    projects: [],
    runs: new Map(),
    issues: new Map(),
    phases: new Map(),
    agentTeams: new Map(),
    agentEvents: new Map(),
    eventLog: [],
    loading: true,
    error: null,
  });

  const [selectedProjectId, setSelectedProjectId] = useState<number | null>(null);
  const [statusFilter, setStatusFilter] = useState<RunStatusFilter>('all');
  const eventIdRef = useRef(0);
  const mountedRef = useRef(true);

  /** Add an event log entry, capping at 500 entries */
  const addLogEntry = useCallback((
    source: EventLogEntry['source'],
    message: string,
    projectName?: string,
    runId?: number,
  ) => {
    setState(prev => ({
      ...prev,
      eventLog: [
        ...prev.eventLog.slice(-499),
        {
          id: String(++eventIdRef.current),
          timestamp: new Date().toISOString(),
          source,
          message,
          projectName,
          runId,
        },
      ],
    }));
  }, []);

  // Load all projects and their active runs on mount
  useEffect(() => {
    mountedRef.current = true;
    let cancelled = false;

    async function loadAll() {
      try {
        const projects = await api.listProjects();
        if (cancelled) return;

        const issueMap = new Map<number, Issue>();
        const runMap = new Map<number, PipelineRun>();
        const phaseMap = new Map<number, PipelinePhase[]>();

        for (const project of projects) {
          try {
            const board = await api.getBoard(project.id);
            if (cancelled) return;
            for (const col of board.columns) {
              for (const item of col.issues) {
                issueMap.set(item.issue.id, item.issue);
                if (item.active_run) {
                  runMap.set(item.active_run.id, item.active_run);
                }
              }
            }
          } catch {
            // Skip projects that fail to load
          }
        }

        if (!cancelled) {
          setState(prev => ({
            ...prev,
            projects,
            issues: issueMap,
            runs: runMap,
            phases: phaseMap,
            loading: false,
          }));
          addLogEntry('system', `Loaded ${projects.length} projects, ${runMap.size} active runs`);
        }
      } catch (err) {
        if (!cancelled) {
          setState(prev => ({
            ...prev,
            loading: false,
            error: err instanceof Error ? err.message : 'Failed to load',
          }));
        }
      }
    }

    loadAll();
    return () => { cancelled = true; mountedRef.current = false; };
  }, [addLogEntry]);

  // WebSocket message handler — uses a ref for issues to avoid stale closure
  const issuesRef = useRef(state.issues);
  issuesRef.current = state.issues;

  useWsSubscribe(useCallback((msg: WsMessage) => {
    if (!mountedRef.current) return;

    switch (msg.type) {
      case 'PipelineStarted': {
        const run = msg.data.run;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          newRuns.set(run.id, run);
          return { ...prev, runs: newRuns };
        });
        const issue = issuesRef.current.get(run.issue_id);
        addLogEntry('system', `Pipeline started for "${issue?.title ?? `issue #${run.issue_id}`}"`, undefined, run.id);
        break;
      }

      case 'PipelineProgress': {
        const { run_id, phase, iteration } = msg.data;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          const existing = newRuns.get(run_id);
          if (existing) {
            newRuns.set(run_id, { ...existing, current_phase: phase, iteration });
          }
          return { ...prev, runs: newRuns };
        });
        break;
      }

      case 'PipelineCompleted': {
        const run = msg.data.run;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          newRuns.set(run.id, run);
          return { ...prev, runs: newRuns };
        });
        addLogEntry('system', 'Pipeline completed successfully', undefined, run.id);
        break;
      }

      case 'PipelineFailed': {
        const run = msg.data.run;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          newRuns.set(run.id, run);
          return { ...prev, runs: newRuns };
        });
        addLogEntry('error', `Pipeline failed: ${run.error ?? 'unknown error'}`, undefined, run.id);
        break;
      }

      case 'PipelinePhaseStarted': {
        const { run_id, phase_number, phase_name } = msg.data;
        setState(prev => {
          const newPhases = new Map(prev.phases);
          const existing = newPhases.get(run_id) ?? [];
          const newPhase: PipelinePhase = {
            id: 0,
            run_id,
            phase_number,
            phase_name,
            status: 'running',
            iteration: null,
            budget: null,
            started_at: new Date().toISOString(),
            completed_at: null,
            error: null,
          };
          newPhases.set(run_id, [...existing, newPhase]);
          return { ...prev, phases: newPhases };
        });
        addLogEntry('phase', `Phase "${phase_name}" started`, undefined, run_id);
        break;
      }

      case 'PipelinePhaseCompleted': {
        const { run_id, phase_number, success } = msg.data;
        setState(prev => {
          const newPhases = new Map(prev.phases);
          const existing = newPhases.get(run_id) ?? [];
          newPhases.set(run_id, existing.map(p =>
            p.phase_number === phase_number
              ? { ...p, status: success ? 'completed' : 'failed', completed_at: new Date().toISOString() }
              : p
          ));
          return { ...prev, phases: newPhases };
        });
        addLogEntry('phase', `Phase completed (${success ? 'success' : 'failed'})`, undefined, run_id);
        break;
      }

      case 'PipelineReviewStarted': {
        addLogEntry('review', 'Review started', undefined, msg.data.run_id);
        break;
      }

      case 'PipelineReviewCompleted': {
        const { passed, findings_count } = msg.data;
        addLogEntry('review', `Review ${passed ? 'passed' : `failed (${findings_count} findings)`}`, undefined, msg.data.run_id);
        break;
      }

      case 'PipelineBranchCreated': {
        const { run_id, branch_name } = msg.data;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          const existing = newRuns.get(run_id);
          if (existing) {
            newRuns.set(run_id, { ...existing, branch_name });
          }
          return { ...prev, runs: newRuns };
        });
        addLogEntry('git', `Branch created: ${branch_name}`, undefined, run_id);
        break;
      }

      case 'PipelinePrCreated': {
        const { run_id, pr_url } = msg.data;
        setState(prev => {
          const newRuns = new Map(prev.runs);
          const existing = newRuns.get(run_id);
          if (existing) {
            newRuns.set(run_id, { ...existing, pr_url });
          }
          return { ...prev, runs: newRuns };
        });
        addLogEntry('git', 'PR created', undefined, run_id);
        break;
      }

      case 'TeamCreated': {
        const { run_id, team_id, strategy, isolation, plan_summary, tasks } = msg.data;
        setState(prev => {
          const newTeams = new Map(prev.agentTeams);
          newTeams.set(run_id, {
            team: { id: team_id, run_id, strategy, isolation, plan_summary, created_at: new Date().toISOString() },
            tasks: tasks ?? [],
          });
          return { ...prev, agentTeams: newTeams };
        });
        addLogEntry('agent', `Agent team created (${strategy})`, undefined, run_id);
        break;
      }

      case 'AgentTaskStarted': {
        addLogEntry('agent', `Task "${msg.data.name}" started (${msg.data.role})`, undefined, undefined);
        break;
      }

      case 'AgentThinking':
      case 'AgentAction':
      case 'AgentOutput':
      case 'AgentSignal': {
        const taskId = msg.data.task_id;
        setState(prev => {
          const newEvents = new Map(prev.agentEvents);
          const taskEvents = newEvents.get(taskId) ?? [];
          const event: AgentEvent = {
            id: taskEvents.length + 1,
            task_id: taskId,
            event_type: msg.type === 'AgentThinking' ? 'thinking'
              : msg.type === 'AgentAction' ? 'action'
              : msg.type === 'AgentOutput' ? 'output'
              : 'signal',
            content: msg.type === 'AgentAction' ? msg.data.summary : msg.data.content,
            metadata: msg.type === 'AgentAction' ? msg.data.metadata : null,
            created_at: new Date().toISOString(),
          };
          newEvents.set(taskId, [...taskEvents.slice(-199), event]);
          return { ...prev, agentEvents: newEvents };
        });
        break;
      }

      case 'IssueCreated': {
        const issue = msg.data.issue;
        setState(prev => {
          const newIssues = new Map(prev.issues);
          newIssues.set(issue.id, issue);
          return { ...prev, issues: newIssues };
        });
        addLogEntry('system', `Issue created: "${issue.title}"`);
        break;
      }

      case 'IssueDeleted': {
        setState(prev => {
          const newIssues = new Map(prev.issues);
          newIssues.delete(msg.data.issue_id);
          return { ...prev, issues: newIssues };
        });
        break;
      }

      case 'ProjectCreated': {
        const project = msg.data.project;
        setState(prev => {
          if (prev.projects.some(p => p.id === project.id)) return prev;
          return { ...prev, projects: [...prev.projects, project] };
        });
        addLogEntry('system', `Project added: "${project.name}"`);
        break;
      }

      case 'ProjectDeleted': {
        const deletedId = msg.data.project_id;
        setState(prev => {
          const newProjects = prev.projects.filter(p => p.id !== deletedId);
          const newIssues = new Map(prev.issues);
          const newRuns = new Map(prev.runs);
          // Remove issues belonging to the deleted project
          for (const [id, issue] of newIssues) {
            if (issue.project_id === deletedId) {
              // Also remove runs for this issue
              for (const [runId, run] of newRuns) {
                if (run.issue_id === id) newRuns.delete(runId);
              }
              newIssues.delete(id);
            }
          }
          return { ...prev, projects: newProjects, issues: newIssues, runs: newRuns };
        });
        addLogEntry('system', 'Project deleted');
        break;
      }
    }
  }, [addLogEntry]));

  // Compute filtered and sorted agent run cards
  const agentRunCards: AgentRunCard[] = useMemo(() => {
    return Array.from(state.runs.values())
      .filter(run => {
        if (selectedProjectId !== null) {
          const issue = state.issues.get(run.issue_id);
          if (issue && issue.project_id !== selectedProjectId) return false;
        }
        if (statusFilter !== 'all' && run.status !== statusFilter) return false;
        return true;
      })
      .sort((a, b) => {
        const diff = (STATUS_ORDER[a.status] ?? 5) - (STATUS_ORDER[b.status] ?? 5);
        if (diff !== 0) return diff;
        return new Date(b.started_at).getTime() - new Date(a.started_at).getTime();
      })
      .map(run => ({
        run,
        issue: state.issues.get(run.issue_id) ?? {
          id: run.issue_id,
          project_id: 0,
          title: `Issue #${run.issue_id}`,
          description: '',
          column: 'backlog' as const,
          position: 0,
          priority: 'medium' as const,
          labels: [],
          github_issue_number: null,
          created_at: '',
          updated_at: '',
        },
        project: state.projects.find(p => {
          const issue = state.issues.get(run.issue_id);
          return issue && p.id === issue.project_id;
        }) ?? { id: 0, name: 'Unknown', path: '', github_repo: null, created_at: '' },
      }));
  }, [state.runs, state.issues, state.projects, selectedProjectId, statusFilter]);

  // Compute idle issue cards — issues without any active pipeline run
  const idleIssueCards: IdleIssueCard[] = useMemo(() => {
    const issueIdsWithRuns = new Set(
      Array.from(state.runs.values()).map(r => r.issue_id)
    );
    return Array.from(state.issues.values())
      .filter(issue => {
        if (issueIdsWithRuns.has(issue.id)) return false;
        if (selectedProjectId !== null && issue.project_id !== selectedProjectId) return false;
        return true;
      })
      .map(issue => ({
        issue,
        project: state.projects.find(p => p.id === issue.project_id)
          ?? { id: 0, name: 'Unknown', path: '', github_repo: null, created_at: '' },
      }));
  }, [state.issues, state.runs, state.projects, selectedProjectId]);

  // Compute status counts (unfiltered — always reflect total state)
  const statusCounts: Record<RunStatusFilter, number> = useMemo(() => {
    const runs = Array.from(state.runs.values());
    return {
      all: runs.length,
      running: runs.filter(r => r.status === 'running').length,
      queued: runs.filter(r => r.status === 'queued').length,
      completed: runs.filter(r => r.status === 'completed').length,
      failed: runs.filter(r => r.status === 'failed').length,
    };
  }, [state.runs]);

  // Actions
  const triggerPipeline = useCallback(async (issueId: number) => {
    const run = await api.triggerPipeline(issueId);
    setState(prev => {
      const newRuns = new Map(prev.runs);
      newRuns.set(run.id, run);
      return { ...prev, runs: newRuns };
    });
  }, []);

  const cancelPipeline = useCallback(async (runId: number) => {
    const run = await api.cancelPipelineRun(runId);
    setState(prev => {
      const newRuns = new Map(prev.runs);
      newRuns.set(run.id, run);
      return { ...prev, runs: newRuns };
    });
  }, []);

  const createIssue = useCallback(async (projectId: number, title: string, description: string) => {
    const issue = await api.createIssue(projectId, title, description);
    setState(prev => {
      const newIssues = new Map(prev.issues);
      newIssues.set(issue.id, issue);
      return { ...prev, issues: newIssues };
    });
    return issue;
  }, []);

  const createProject = useCallback(async (name: string, path: string) => {
    const project = await api.createProject(name, path);
    setState(prev => ({
      ...prev,
      projects: [...prev.projects, project],
    }));
    return project;
  }, []);

  const cloneProject = useCallback(async (repoUrl: string) => {
    const project = await api.cloneProject(repoUrl);
    setState(prev => ({
      ...prev,
      projects: [...prev.projects, project],
    }));
    return project;
  }, []);

  const deleteProject = useCallback(async (projectId: number) => {
    await api.deleteProject(projectId);
    // Optimistic removal — WS message will also trigger state cleanup
    setState(prev => ({
      ...prev,
      projects: prev.projects.filter(p => p.id !== projectId),
    }));
  }, []);

  const refresh = useCallback(async () => {
    setState(prev => ({ ...prev, loading: true }));
    try {
      const projects = await api.listProjects();
      const issueMap = new Map<number, Issue>();
      const runMap = new Map<number, PipelineRun>();
      for (const project of projects) {
        try {
          const board = await api.getBoard(project.id);
          for (const col of board.columns) {
            for (const item of col.issues) {
              issueMap.set(item.issue.id, item.issue);
              if (item.active_run) {
                runMap.set(item.active_run.id, item.active_run);
              }
            }
          }
        } catch { /* skip */ }
      }
      setState(prev => ({
        ...prev,
        projects,
        issues: issueMap,
        runs: runMap,
        loading: false,
        error: null,
      }));
    } catch (err) {
      setState(prev => ({
        ...prev,
        loading: false,
        error: err instanceof Error ? err.message : 'Refresh failed',
      }));
    }
  }, []);

  // Compute issue counts grouped by project ID
  const issuesByProject = useMemo(() => {
    const map = new Map<number, number>();
    for (const issue of state.issues.values()) {
      map.set(issue.project_id, (map.get(issue.project_id) ?? 0) + 1);
    }
    return map;
  }, [state.issues]);

  return {
    projects: state.projects,
    agentRunCards,
    statusCounts,
    eventLog: state.eventLog,
    phases: state.phases,
    agentTeams: state.agentTeams,
    agentEvents: state.agentEvents,
    loading: state.loading,
    error: state.error,
    selectedProjectId,
    setSelectedProjectId,
    statusFilter,
    setStatusFilter,
    triggerPipeline,
    cancelPipeline,
    createIssue,
    createProject,
    cloneProject,
    deleteProject,
    refresh,
    issuesByProject,
  };
}

import { useState, useCallback, useMemo } from 'react';
import type { ViewMode, Project } from './types';
import useMissionControl from './hooks/useMissionControl';
import { WebSocketProvider } from './contexts/WebSocketContext';
import StatusBar from './components/StatusBar';
import ProjectSidebar from './components/ProjectSidebar';
import AgentRunCard from './components/AgentRunCard';
import EventLog from './components/EventLog';
import FloatingActionButton from './components/FloatingActionButton';
import NewIssueModal from './components/NewIssueModal';
import ConfirmDialog from './components/ConfirmDialog';
import { ProjectSetup } from './components/ProjectSetup';
import { api } from './api/client';

/**
 * Mission Control dashboard — the main application shell.
 * Aggregates all projects and agent runs into a unified monitoring view.
 * Layout: StatusBar (top) -> flex row [ProjectSidebar | Agent Grid] -> EventLog (bottom).
 */
function MissionControl() {
  const {
    projects,
    agentRunCards,
    statusCounts,
    eventLog,
    phases,
    agentTeams,
    agentEvents,
    loading,
    selectedProjectId,
    setSelectedProjectId,
    triggerPipeline,
    cancelPipeline,
    createIssue,
    createProject,
    cloneProject,
    deleteProject,
    issuesByProject,
  } = useMissionControl();

  const [viewMode, setViewMode] = useState<ViewMode>('grid');
  const [showNewIssueModal, setShowNewIssueModal] = useState(false);
  const [newIssueProjectId, setNewIssueProjectId] = useState<number | null>(null);
  const [showProjectSetup, setShowProjectSetup] = useState(false);
  const [deleteConfirm, setDeleteConfirm] = useState<{ id: number; name: string } | null>(null);

  /** Compute run counts by project for the sidebar */
  const runsByProject = useMemo(() => {
    const map = new Map<number, { running: number; total: number }>();
    for (const card of agentRunCards) {
      const pid = card.project.id;
      const existing = map.get(pid) ?? { running: 0, total: 0 };
      existing.total++;
      if (card.run.status === 'running') existing.running++;
      map.set(pid, existing);
    }
    return map;
  }, [agentRunCards]);

  /** Projects filtered by the current sidebar selection */
  const displayedProjects = useMemo(() => {
    if (selectedProjectId === null) return projects;
    return projects.filter(p => p.id === selectedProjectId);
  }, [projects, selectedProjectId]);

  const handleNewIssue = useCallback(() => {
    setNewIssueProjectId(null);
    setShowNewIssueModal(true);
  }, []);

  const handleNewProject = useCallback(() => {
    setShowProjectSetup(true);
  }, []);

  const handleSyncGithub = useCallback(async () => {
    const project = projects.find(p =>
      selectedProjectId === null ? true : p.id === selectedProjectId
    );
    if (project) {
      try {
        await api.syncGithub(project.id);
      } catch (err) {
        console.error('Sync failed:', err);
      }
    }
  }, [projects, selectedProjectId]);

  const handleIssueSubmit = useCallback(async (projectId: number, title: string, description: string) => {
    const issue = await createIssue(projectId, title, description);
    await triggerPipeline(issue.id);
  }, [createIssue, triggerPipeline]);

  const handleProjectSelect = useCallback((project: Project) => {
    setSelectedProjectId(project.id);
    setShowProjectSetup(false);
  }, [setSelectedProjectId]);

  const handleProjectCreate = useCallback((name: string, path: string) => {
    createProject(name, path).then(() => {
      setShowProjectSetup(false);
    }).catch(console.error);
  }, [createProject]);

  const handleCloneProject = useCallback(async (repoUrl: string) => {
    const project = await cloneProject(repoUrl);
    setShowProjectSetup(false);
    setSelectedProjectId(project.id);
  }, [cloneProject, setSelectedProjectId]);

  const handleDeleteProject = useCallback(async (projectId: number) => {
    await deleteProject(projectId);
    if (selectedProjectId === projectId) {
      setSelectedProjectId(null);
    }
  }, [deleteProject, selectedProjectId, setSelectedProjectId]);

  // Loading state
  if (loading) {
    return (
      <div style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        height: '100vh',
        backgroundColor: 'var(--color-bg-primary)',
        color: 'var(--color-text-primary)',
        gap: '12px',
        fontSize: '14px',
      }}>
        <span className="pulse-dot" style={{
          width: '8px',
          height: '8px',
          borderRadius: '50%',
          backgroundColor: 'var(--color-success)',
        }} />
        Initializing Mission Control...
      </div>
    );
  }

  // No projects — show ProjectSetup full-screen
  if (projects.length === 0) {
    return (
      <div style={{
        height: '100vh',
        backgroundColor: 'var(--color-bg-primary)',
      }}>
        <ProjectSetup
          projects={[]}
          onSelect={handleProjectSelect}
          onCreate={handleProjectCreate}
          onClone={handleCloneProject}
        />
      </div>
    );
  }

  return (
    <div style={{
      display: 'flex',
      flexDirection: 'column',
      height: '100vh',
      backgroundColor: 'var(--color-bg-primary)',
      color: 'var(--color-text-primary)',
    }}>
      {/* Top bar */}
      <StatusBar
        agentCounts={{
          running: statusCounts.running,
          queued: statusCounts.queued,
          completed: statusCounts.completed,
          failed: statusCounts.failed,
        }}
        projectCount={projects.length}
        viewMode={viewMode}
        onViewModeChange={setViewMode}
      />

      {/* Main content: sidebar + agent grid */}
      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>
        <ProjectSidebar
          projects={projects}
          selectedProjectId={selectedProjectId}
          onSelectProject={setSelectedProjectId}
          onDeleteProject={(id, name) => setDeleteConfirm({ id, name })}
          runsByProject={runsByProject}
        />

        {/* Agent run grid */}
        <div style={{
          flex: 1,
          overflowY: 'auto',
          padding: '16px',
        }}>
          {agentRunCards.length === 0 ? (
            <div style={{
              display: viewMode === 'grid' ? 'grid' : 'flex',
              gridTemplateColumns: viewMode === 'grid' ? 'repeat(auto-fill, minmax(400px, 1fr))' : undefined,
              flexDirection: viewMode === 'list' ? 'column' : undefined,
              gap: '12px',
            }}>
              {displayedProjects.map(project => {
                const issueCount = issuesByProject.get(project.id) ?? 0;
                return (
                  <div
                    key={project.id}
                    style={{
                      backgroundColor: 'var(--color-bg-card)',
                      border: '1px solid var(--color-border)',
                      borderLeft: '3px solid var(--color-text-secondary)',
                    }}
                  >
                    <div style={{
                      display: 'flex',
                      alignItems: 'center',
                      padding: '12px',
                      gap: '12px',
                    }}>
                      {/* Idle dot */}
                      <span style={{
                        width: '8px',
                        height: '8px',
                        borderRadius: '50%',
                        backgroundColor: 'var(--color-text-secondary)',
                        flexShrink: 0,
                      }} />

                      {/* Project name */}
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{
                          fontSize: '13px',
                          fontWeight: 600,
                          overflow: 'hidden',
                          textOverflow: 'ellipsis',
                          whiteSpace: 'nowrap',
                        }}>
                          {project.name}
                        </div>
                        <div style={{
                          fontSize: '11px',
                          color: 'var(--color-text-secondary)',
                          marginTop: '2px',
                        }}>
                          {issueCount} {issueCount === 1 ? 'issue' : 'issues'}
                        </div>
                      </div>

                      {/* Status label */}
                      <span style={{
                        fontSize: '11px',
                        color: 'var(--color-text-secondary)',
                        fontWeight: 600,
                        flexShrink: 0,
                      }}>
                        IDLE
                      </span>

                      {/* Create Issue button */}
                      <button
                        onClick={() => {
                          setNewIssueProjectId(project.id);
                          setShowNewIssueModal(true);
                        }}
                        style={{
                          padding: '4px 10px',
                          fontSize: '11px',
                          fontFamily: 'inherit',
                          background: 'transparent',
                          border: '1px solid var(--color-border)',
                          color: 'var(--color-success)',
                          cursor: 'pointer',
                          flexShrink: 0,
                        }}
                        onMouseEnter={e => (e.currentTarget.style.backgroundColor = 'var(--color-bg-card-hover)')}
                        onMouseLeave={e => (e.currentTarget.style.backgroundColor = 'transparent')}
                      >
                        + Issue
                      </button>

                      {/* Delete project button */}
                      <button
                        onClick={() => setDeleteConfirm({ id: project.id, name: project.name })}
                        style={{
                          padding: '4px 8px',
                          fontSize: '11px',
                          fontFamily: 'inherit',
                          background: 'transparent',
                          border: '1px solid var(--color-border)',
                          color: 'var(--color-text-secondary)',
                          cursor: 'pointer',
                          flexShrink: 0,
                        }}
                        onMouseEnter={e => {
                          e.currentTarget.style.backgroundColor = 'var(--color-bg-card-hover)';
                          e.currentTarget.style.color = 'var(--color-error)';
                          e.currentTarget.style.borderColor = 'var(--color-error)';
                        }}
                        onMouseLeave={e => {
                          e.currentTarget.style.backgroundColor = 'transparent';
                          e.currentTarget.style.color = 'var(--color-text-secondary)';
                          e.currentTarget.style.borderColor = 'var(--color-border)';
                        }}
                        title="Delete project"
                      >
                        ✕
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          ) : (
            <div style={{
              display: viewMode === 'grid' ? 'grid' : 'flex',
              gridTemplateColumns: viewMode === 'grid' ? 'repeat(auto-fill, minmax(400px, 1fr))' : undefined,
              flexDirection: viewMode === 'list' ? 'column' : undefined,
              gap: '12px',
            }}>
              {agentRunCards.map(card => (
                <AgentRunCard
                  key={card.run.id}
                  card={card}
                  phases={phases.get(card.run.id)}
                  agentTeam={agentTeams.get(card.run.id)}
                  agentEvents={agentEvents}
                  onCancel={cancelPipeline}
                  viewMode={viewMode}
                />
              ))}
            </div>
          )}
        </div>
      </div>

      {/* Bottom event log */}
      <EventLog entries={eventLog} />

      {/* Floating action button */}
      <FloatingActionButton
        onNewIssue={handleNewIssue}
        onNewProject={handleNewProject}
        onSyncGithub={handleSyncGithub}
      />

      {/* New Issue Modal */}
      {showNewIssueModal && (
        <NewIssueModal
          projects={projects}
          defaultProjectId={newIssueProjectId}
          onSubmit={handleIssueSubmit}
          onClose={() => { setShowNewIssueModal(false); setNewIssueProjectId(null); }}
        />
      )}

      {/* Delete Confirmation Dialog */}
      {deleteConfirm && (
        <ConfirmDialog
          title="Delete project"
          message={`Delete "${deleteConfirm.name}"? This will remove all its issues and pipeline runs.`}
          confirmLabel="Delete"
          onConfirm={() => {
            handleDeleteProject(deleteConfirm.id);
            setDeleteConfirm(null);
          }}
          onCancel={() => setDeleteConfirm(null)}
        />
      )}

      {/* Project Setup Modal */}
      {showProjectSetup && (
        <div
          data-testid="project-setup-modal"
          onClick={() => setShowProjectSetup(false)}
          style={{
            position: 'fixed',
            inset: 0,
            backgroundColor: 'rgba(0,0,0,0.7)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 100,
          }}
        >
          <div onClick={e => e.stopPropagation()} style={{ width: '100%', maxWidth: '500px' }}>
            <ProjectSetup
              projects={projects}
              onSelect={handleProjectSelect}
              onCreate={handleProjectCreate}
              onClone={handleCloneProject}
            />
          </div>
        </div>
      )}
    </div>
  );
}

function App() {
  const wsUrl = `${window.location.protocol === 'https:' ? 'wss:' : 'ws:'}//${window.location.host}/ws`;
  return (
    <WebSocketProvider url={wsUrl}>
      <MissionControl />
    </WebSocketProvider>
  );
}

export default App;

